module sky130_fd_sc_hd__xor3_1 (
    X,
    A,
    B,
    C
);

    output X;
    input  A;
    input  B;
    input  C;

    // Voltage supply signals
    supply1 VPWR;
    supply0 VGND;
    supply1 VPB ;
    supply0 VNB ;

    sky130_fd_sc_hd__xor3 base (
        .X(X),
        .A(A),
        .B(B),
        .C(C)
    );


    specify
    if ((!B&!C)) (A +=> X) = (0:0:0,0:0:0);
    if ((!B&C)) (A -=> X) = (0:0:0,0:0:0);
    if ((B&!C)) (A -=> X) = (0:0:0,0:0:0);
    if ((B&C)) (A +=> X) = (0:0:0,0:0:0);
    if ((!A&!C)) (B +=> X) = (0:0:0,0:0:0);
    if ((!A&C)) (B -=> X) = (0:0:0,0:0:0);
    if ((A&!C)) (B -=> X) = (0:0:0,0:0:0);
    if ((A&C)) (B +=> X) = (0:0:0,0:0:0);
    if ((!A&!B)) (C +=> X) = (0:0:0,0:0:0);
    if ((!A&B)) (C -=> X) = (0:0:0,0:0:0);
    if ((A&!B)) (C -=> X) = (0:0:0,0:0:0);
    if ((A&B)) (C +=> X) = (0:0:0,0:0:0);
    endspecify

endmodule

